+package main
+
+import (
+	"encoding/json"
+	"fmt"
+	"os"
+	"path/filepath"
+	"sync"
+	"time"
+
+	"github.com/prometheus/prometheus/config"
+	api_v1 "github.com/prometheus/prometheus/web/api/v1"
+)
+
+const transactionalReloadStateFilename = "transactional-reload-state.json"
+
+// transactionalReloadState owns the last known-good configuration and the
+// externally visible result of the most recent reload attempt.
+type transactionalReloadState struct {
+	mu        sync.RWMutex
+	dir       string
+	lastGood  *config.Config
+	outcome   api_v1.ReloadStatus
+}
+
+func newTransactionalReloadState(dir string) *transactionalReloadState {
+	s := &transactionalReloadState{dir: dir, outcome: emptyReloadStatus()}
+	b, err := os.ReadFile(filepath.Join(dir, transactionalReloadStateFilename))
+	if err != nil {
+		return s
+	}
+	var outcome api_v1.ReloadStatus
+	if json.Unmarshal(b, &outcome) == nil && validReloadStatus(outcome) {
+		s.outcome = outcome
+	}
+	return s
+}
+
+func emptyReloadStatus() api_v1.ReloadStatus {
+	return api_v1.ReloadStatus{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}
+}
+
+func validReloadStatus(s api_v1.ReloadStatus) bool {
+	switch s.ErrorCategory {
+	case "none", "load_error", "apply_error", "rollback_error":
+		return true
+	default:
+		return false
+	}
+}
+
+func (s *transactionalReloadState) Status() api_v1.ReloadStatus {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	return s.outcome.Clone()
+}
+
+func (s *transactionalReloadState) setLastGood(conf *config.Config) {
+	s.mu.Lock()
+	defer s.mu.Unlock()
+	s.lastGood = conf
+}
+
+func (s *transactionalReloadState) knownGood() *config.Config {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	return s.lastGood
+}
+
+func (s *transactionalReloadState) record(outcome api_v1.ReloadStatus) {
+	s.mu.Lock()
+	s.outcome = outcome.Clone()
+	s.mu.Unlock()
+
+	// Best effort persistence deliberately never turns a reload result into a
+	// reload failure. A later restart must also tolerate a missing/corrupt file.
+	b, err := json.Marshal(outcome)
+	if err != nil {
+		return
+	}
+	tmp, err := os.CreateTemp(s.dir, ".transactional-reload-state-*")
+	if err != nil {
+		return
+	}
+	name := tmp.Name()
+	if _, err = tmp.Write(b); err == nil {
+		err = tmp.Chmod(0o644)
+	}
+	if closeErr := tmp.Close(); err == nil {
+		err = closeErr
+	}
+	if err == nil {
+		err = os.Rename(name, filepath.Join(s.dir, transactionalReloadStateFilename))
+	}
+	if err != nil {
+		_ = os.Remove(name)
+	}
+}
+
+func reloadConfigTransactionally(filename string, enableExemplarStorage bool, logger interface{ Info(string, ...any); Error(string, ...any) }, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), state *transactionalReloadState, rls ...reloader) error {
+	// Keep the load stage separate: a malformed config has not changed runtime
+	// state and therefore must never trigger a rollback.
+	conf, err := config.LoadFile(filename, agentMode, logger.(*slog.Logger))
+	if err != nil {
+		outcome := emptyReloadStatus()
+		outcome.LastReloadID = time.Now().UTC().Format(time.RFC3339)
+		outcome.ErrorCategory = "load_error"
+		outcome.ErrorMessage = fmt.Sprintf("couldn't load configuration (--config.file=%q): %v", filename, err)
+		state.record(outcome)
+		callback(false)
+		return errors.New(outcome.ErrorMessage)
+	}
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	outcome := emptyReloadStatus()
+	outcome.LastReloadID = time.Now().UTC().Format(time.RFC3339)
+	for _, rl := range rls {
+		started := time.Now()
+		err := rl.reloader(conf)
+		outcome.ReloaderTimingsMS[rl.name] = time.Since(started).Milliseconds()
+		if err != nil {
+			outcome.ErrorCategory = "apply_error"
+			outcome.ErrorMessage = err.Error()
+			outcome.FailedReloader = rl.name
+			if len(outcome.AppliedReloaders) > 0 {
+				outcome.RollbackAttempted = true
+				good := state.knownGood()
+				for _, rollback := range rls {
+					if rollbackErr := rollback.reloader(good); rollbackErr != nil {
+						outcome.ErrorCategory = "rollback_error"
+						outcome.ErrorMessage = fmt.Sprintf("apply %s: %v; rollback %s: %v", rl.name, err, rollback.name, rollbackErr)
+						break
+					}
+				}
+				outcome.RollbackSuccessful = outcome.ErrorCategory != "rollback_error"
+			}
+			state.record(outcome)
+			callback(false)
+			return fmt.Errorf("failed to apply configuration in reloader %q: %w", rl.name, err)
+		}
+		outcome.AppliedReloaders = append(outcome.AppliedReloaders, rl.name)
+	}
+
+	updateGoGC(conf, logger.(*slog.Logger))
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	outcome.LastReloadSuccessful = true
+	state.setLastGood(conf)
+	state.record(outcome)
+	callback(true)
+	return nil
+}
