const transactionalReloadStateFilename = "transactional-reload-state.json"

// transactionalReloadState owns the last known-good configuration and the
// externally visible result of the most recent reload attempt.
type transactionalReloadState struct {
	mu       sync.RWMutex
	dir      string
	lastGood *config.Config
	outcome  api_v1.ReloadStatus
}

func newTransactionalReloadState(dir string) *transactionalReloadState {
	s := &transactionalReloadState{dir: dir, outcome: emptyReloadStatus()}
	b, err := os.ReadFile(filepath.Join(dir, transactionalReloadStateFilename))
	if err != nil {
		return s
	}
	var outcome api_v1.ReloadStatus
	if json.Unmarshal(b, &outcome) == nil && validReloadStatus(outcome) {
		s.outcome = outcome
	}
	return s
}

func emptyReloadStatus() api_v1.ReloadStatus {
	return api_v1.ReloadStatus{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}
}

func validReloadStatus(s api_v1.ReloadStatus) bool {
	switch s.ErrorCategory {
	case "none", "load_error", "apply_error", "rollback_error":
		return true
	default:
		return false
	}
}

func (s *transactionalReloadState) Status() api_v1.ReloadStatus {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return s.outcome.Clone()
}

func (s *transactionalReloadState) setLastGood(conf *config.Config) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.lastGood = conf
}

func (s *transactionalReloadState) knownGood() *config.Config {
